Interactive: Build a Signal
Drag the sliders below. Watch what happens to the wave.
//| echo: false

viewof amplitude = Inputs.range([0.5, 10], {
  value: 5,
  step: 0.1,
  label: "Amplitude (μV)"
})

viewof frequency = Inputs.range([0.5, 30], {
  value: 10,
  step: 0.5,
  label: "Frequency (Hz)"
})
//| echo: false

{
  const width = 700;
  const height = 280;
  const margin = {top: 20, right: 20, bottom: 40, left: 55};

  const duration = 2; // seconds
  const sampleRate = 500;
  const nPoints = duration * sampleRate;

  // Generate signal
  const data = Array.from({length: nPoints}, (_, i) =&gt; {
    const t = i / sampleRate;
    const y = amplitude * Math.sin(2 * Math.PI * frequency * t);
    return {t, y};
  });

  const svg = d3.create("svg")
    .attr("viewBox", [0, 0, width, height])
    .attr("width", width)
    .attr("height", height)
    .style("background", "#fafafa")
    .style("border-radius", "8px");

  const x = d3.scaleLinear()
    .domain([0, duration])
    .range([margin.left, width - margin.right]);

  const y = d3.scaleLinear()
    .domain([-12, 12])
    .range([height - margin.bottom, margin.top]);

  // Grid lines
  svg.append("g")
    .attr("stroke", "#eee")
    .attr("stroke-width", 0.5)
    .selectAll("line")
    .data(y.ticks(8))
    .join("line")
    .attr("x1", margin.left)
    .attr("x2", width - margin.right)
    .attr("y1", d =&gt; y(d))
    .attr("y2", d =&gt; y(d));

  // Zero line
  svg.append("line")
    .attr("x1", margin.left)
    .attr("x2", width - margin.right)
    .attr("y1", y(0))
    .attr("y2", y(0))
    .attr("stroke", "#bbb")
    .attr("stroke-width", 1)
    .attr("stroke-dasharray", "4,3");

  // Signal line
  const line = d3.line()
    .x(d =&gt; x(d.t))
    .y(d =&gt; y(d.y))
    .curve(d3.curveLinear);

  svg.append("path")
    .datum(data)
    .attr("fill", "none")
    .attr("stroke", "#2980b9")
    .attr("stroke-width", 2)
    .attr("d", line);

  // Amplitude annotation
  if (amplitude &gt; 1) {
    const peakT = 1 / (4 * frequency); // first peak
    if (peakT &lt; duration) {
      svg.append("line")
        .attr("x1", x(peakT)).attr("x2", x(peakT))
        .attr("y1", y(0)).attr("y2", y(amplitude))
        .attr("stroke", "#e74c3c")
        .attr("stroke-width", 1.5)
        .attr("stroke-dasharray", "3,2");

      svg.append("text")
        .attr("x", x(peakT) + 6)
        .attr("y", y(amplitude / 2))
        .attr("fill", "#e74c3c")
        .attr("font-size", "12px")
        .attr("font-weight", "600")
        .text(`${amplitude.toFixed(1)} μV`);
    }
  }

  // Period annotation
  if (frequency &lt;= 15) {
    const period = 1 / frequency;
    const startT = 0;
    if (startT + period &lt; duration) {
      svg.append("line")
        .attr("x1", x(startT)).attr("x2", x(startT + period))
        .attr("y1", y(-amplitude - 1.5)).attr("y2", y(-amplitude - 1.5))
        .attr("stroke", "#27ae60")
        .attr("stroke-width", 1.5);

      // Arrow heads
      svg.append("line")
        .attr("x1", x(startT)).attr("x2", x(startT) + 5)
        .attr("y1", y(-amplitude - 1.5)).attr("y2", y(-amplitude - 1.5) - 4)
        .attr("stroke", "#27ae60").attr("stroke-width", 1.5);
      svg.append("line")
        .attr("x1", x(startT)).attr("x2", x(startT) + 5)
        .attr("y1", y(-amplitude - 1.5)).attr("y2", y(-amplitude - 1.5) + 4)
        .attr("stroke", "#27ae60").attr("stroke-width", 1.5);

      svg.append("text")
        .attr("x", x(startT + period / 2))
        .attr("y", y(-amplitude - 1.5) + 16)
        .attr("fill", "#27ae60")
        .attr("font-size", "11px")
        .attr("font-weight", "600")
        .attr("text-anchor", "middle")
        .text(`1 cycle = ${(period * 1000).toFixed(0)} ms`);
    }
  }

  // Axes
  svg.append("g")
    .attr("transform", `translate(0,${height - margin.bottom})`)
    .call(d3.axisBottom(x).ticks(5).tickFormat(d =&gt; d + " s"))
    .call(g =&gt; g.select(".domain").attr("stroke", "#999"));

  svg.append("g")
    .attr("transform", `translate(${margin.left},0)`)
    .call(d3.axisLeft(y).ticks(6).tickFormat(d =&gt; d + " μV"))
    .call(g =&gt; g.select(".domain").attr("stroke", "#999"));

  // Title
  svg.append("text")
    .attr("x", width / 2)
    .attr("y", 14)
    .attr("text-anchor", "middle")
    .attr("font-size", "13px")
    .attr("fill", "#555")
    .text(`${frequency} Hz signal — ${amplitude.toFixed(1)} μV amplitude`);

  return svg.node();
}

Experiment:

Set the frequency to 10 Hz. This is roughly the speed of the alpha rhythm — the dominant EEG wave when you close your eyes.
Now crank it to 1 Hz. This is the delta range — slow waves you see in deep sleep.
Set amplitude to 2 μV — that’s a weak EEG signal. Now set it to 10 μV — stronger. In real EEG, amplitudes are typically 10–100 μV.

Quiz: Check Your Understanding
//| echo: false

// Quiz state
viewof q1answer = Inputs.radio(
  new Map([
    ["A. It means the signal is faster", "a"],
    ["B. It means the voltage is higher — more electrical activity is reaching the electrode", "b"],
    ["C. It means the electrode is closer to the source", "c"],
    ["D. It means the patient is awake", "d"]
  ]),
  {label: "Q1: A signal has a larger amplitude. What does that tell you?"}
)
//| echo: false
q1feedback = {
  if (q1answer === "b") return html`&lt;div class="quiz-feedback-correct"&gt;✓ Correct. Amplitude = voltage magnitude. A bigger wave means more electrical activity is being picked up.&lt;/div&gt;`;
  if (q1answer === "c") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ Not quite. Electrode distance affects amplitude, but amplitude itself is a property of the signal — it tells you the voltage, not the distance.&lt;/div&gt;`;
  if (q1answer === "a") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ That would be frequency, not amplitude. Try again.&lt;/div&gt;`;
  if (q1answer === "d") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ Wakefulness can affect amplitude, but amplitude itself just describes how tall the wave is.&lt;/div&gt;`;
  return html`&lt;div class="quiz-feedback-hint"&gt;Select an answer above.&lt;/div&gt;`;
}

//| echo: false

viewof q2answer = Inputs.radio(
  new Map([
    ["A. 0.5 Hz — about one beat every two seconds", "a"],
    ["B. About 1.2 Hz — roughly 70 beats per minute", "b"],
    ["C. 10 Hz — the same as EEG alpha rhythm", "c"],
    ["D. 60 Hz — one beat per second", "d"]
  ]),
  {label: "Q2: A healthy resting heart rate is about 70 beats per minute. What is the frequency of the ECG signal?"}
)
//| echo: false
q2feedback = {
  if (q2answer === "b") return html`&lt;div class="quiz-feedback-correct"&gt;✓ Correct. 70 bpm ÷ 60 seconds = ~1.17 Hz. Each cardiac cycle takes about 0.85 seconds.&lt;/div&gt;`;
  if (q2answer === "d") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ Careful — 60 beats per minute would be 1 Hz, not 60 Hz. Frequency in Hz = beats per &lt;em&gt;second&lt;/em&gt;.&lt;/div&gt;`;
  if (q2answer === "a") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ That's too slow — 0.5 Hz would mean 30 bpm (severe bradycardia).&lt;/div&gt;`;
  if (q2answer === "c") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ 10 Hz would mean 600 bpm — the patient would not be doing well.&lt;/div&gt;`;
  return html`&lt;div class="quiz-feedback-hint"&gt;Select an answer above.&lt;/div&gt;`;
}

//| echo: false

viewof q3answer = Inputs.radio(
  new Map([
    ["A. More neurons are firing at higher frequency", "a"],
    ["B. More neurons are firing in synchrony, so their voltages add up", "b"],
    ["C. The electrodes are more sensitive to slow signals", "c"],
    ["D. The skull filters out fast signals more than slow ones", "d"]
  ]),
  {label: "Q3: Slow EEG rhythms (like delta during sleep) have much larger amplitude than fast rhythms (like gamma). Why?"}
)
//| echo: false
q3feedback = {
  if (q3answer === "b") return html`&lt;div class="quiz-feedback-correct"&gt;✓ Correct. Slow rhythms reflect large populations of neurons firing together. Their individual tiny voltages sum up — like a stadium crowd doing a synchronized wave vs. everyone clapping at different times.&lt;/div&gt;`;
  if (q3answer === "d") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ The skull does attenuate signals, but that's not the main reason for the amplitude difference across frequency bands. Think about what the neurons are doing.&lt;/div&gt;`;
  if (q3answer === "a") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ It's not about individual neurons firing faster — it's about how many fire &lt;em&gt;together&lt;/em&gt;.&lt;/div&gt;`;
  if (q3answer === "c") return html`&lt;div class="quiz-feedback-incorrect"&gt;✗ The electrodes don't have a frequency preference. The voltage difference comes from the brain itself.&lt;/div&gt;`;
  return html`&lt;div class="quiz-feedback-hint"&gt;Select an answer above.&lt;/div&gt;`;
}
